import React, { useEffect, useState } from 'react';
import axios from 'axios';
import BlogCard from '../components/BlogCard';

const HomePage = () => {
  const [blogs, setBlogs] = useState([]);
  const [filteredBlogs, setFilteredBlogs] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const API_BASE_URL = process.env.REACT_APP_API_BASE_URL;

  useEffect(() => {
    const fetchBlogsAndCategories = async () => {
      try {
        const blogRes = await axios.get(`${API_BASE_URL}/blogs`);
        const categoryRes = await axios.get(`${API_BASE_URL}/category`);
        setBlogs(blogRes.data);
        setCategories(categoryRes.data);
        setFilteredBlogs(blogRes.data);
        setLoading(false);
      } catch (err) {
        setError('Failed to load data.');
        setLoading(false);
      }
    };

    fetchBlogsAndCategories();
  }, [API_BASE_URL]);

  const handleCategoryChange = (categoryName) => {
    setSelectedCategory(categoryName);
    if (categoryName === 'All') {
      setFilteredBlogs(blogs);
    } else {
      setFilteredBlogs(blogs.filter((blog) => blog.category_name === categoryName));
    }
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Are you sure you want to delete this blog?");
    if (!confirmDelete) return;

    try {
      await axios.delete(`${API_BASE_URL}/blogs/${id}`);
      const updatedBlogs = blogs.filter((blog) => blog.id !== id);
      setBlogs(updatedBlogs);
      setFilteredBlogs(
        selectedCategory === 'All'
          ? updatedBlogs
          : updatedBlogs.filter((blog) => blog.category_name === selectedCategory)
      );
    } catch (err) {
      console.error("Error deleting blog:", err);
    }
  };

  const isAdmin = localStorage.getItem('role') === 'admin';

  if (loading) return <p className="text-center text-gray-500">Loading...</p>;
  if (error) return <p className="text-center text-red-500">{error}</p>;

  return (
    <div className="container mx-auto p-4">
      <div className="mb-6 flex flex-wrap gap-3 justify-center">
        <button
          onClick={() => handleCategoryChange('All')}
          className={`px-4 py-2 rounded-full ${selectedCategory === 'All' ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-700'}`}
        >
          All
        </button>
        {categories.map((category) => (
          <button
            key={category.id}
            onClick={() => handleCategoryChange(category.name)}
            className={`px-4 py-2 rounded-full ${selectedCategory === category.name ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-700'}`}
          >
            {category.name}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredBlogs
          .filter(blog => blog && typeof blog === 'object' && blog.id) // ✅ safe filter added
          .map((blog) => (
            <BlogCard key={blog.id} blog={blog} onDelete={handleDelete} isAdmin={isAdmin} />
          ))}
      </div>
    </div>
  );
};

export default HomePage;
